 25→public class MaxLineLengthRule :
 26→    StandardRule(
 27→        id = "max-line-length",
 28→        visitorModifiers =
 29→            setOf(
 30→                VisitorModifier.RunAfterRule(
 31→                    // This rule should run after all other rules. Each time a rule visitor is modified with
 32→                    // RunAsLateAsPossible, it needs to be checked that this rule still runs after that new rule or that it
 33→                    // won't be affected by that rule.
 34→                    ruleId = TRAILING_COMMA_ON_CALL_SITE_RULE_ID,
 35→                    mode = REGARDLESS_WHETHER_RUN_AFTER_RULE_IS_LOADED_OR_DISABLED,
 36→                ),
 37→                VisitorModifier.RunAfterRule(
 38→                    // This rule should run after all other rules. Each time a rule visitor is modified with
 39→                    // RunAsLateAsPossible, it needs to be checked that this rule still runs after that new rule or that it
 40→                    // won't be affected by that rule.
 41→                    ruleId = TRAILING_COMMA_ON_DECLARATION_SITE_RULE_ID,
 42→                    mode = REGARDLESS_WHETHER_RUN_AFTER_RULE_IS_LOADED_OR_DISABLED,
 43→                ),
 44→                VisitorModifier.RunAsLateAsPossible,
 45→            ),
 46→        usesEditorConfigProperties =
 47→            setOf(
 48→                MAX_LINE_LENGTH_PROPERTY,
 49→                IGNORE_BACKTICKED_IDENTIFIER_PROPERTY,
 50→            ),
 51→    ) {
 52→    private var maxLineLength: Int = MAX_LINE_LENGTH_PROPERTY.defaultValue
 53→    private var rangeTree = RangeTree()
 54→    private var ignoreBackTickedIdentifier = IGNORE_BACKTICKED_IDENTIFIER_PROPERTY.defaultValue
 55→
 56→    override fun beforeFirstNode(editorConfig: EditorConfig) {
 57→        ignoreBackTickedIdentifier = editorConfig[IGNORE_BACKTICKED_IDENTIFIER_PROPERTY]
 58→        maxLineLength = editorConfig[MAX_LINE_LENGTH_PROPERTY]
 59→        if (maxLineLength == MAX_LINE_LENGTH_PROPERTY_OFF) {
 60→            stopTraversalOfAST()
 61→        }
 62→    }
 63→
 64→    override fun beforeVisitChildNodes(
 65→        node: ASTNode,
 66→        autoCorrect: Boolean,
 67→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 68→    ) {
 69→        if (node.isRoot()) {
 70→            val errorOffset = arrayListOf<Int>()
 71→            node
 72→                .getElementsPerLine()
 73→                .filter { it.lineLength(ignoreBackTickedIdentifier) > maxLineLength }
 74→                .forEach { parsedLine ->
 75→                    val el = parsedLine.elements.last()
 76→                    if (!el.isPartOf(KDoc::class) && !el.isPartOfRawMultiLineString()) {
 77→                        if (!el.isPartOf(PsiComment::class)) {
 78→                            if (!el.isPartOf(KtPackageDirective::class) && !el.isPartOf(KtImportDirective::class)) {
 79→                                // fixme:
 80→                                // normally we would emit here but due to API limitations we need to hold off until
 81→                                // node spanning the same offset is 'visit'ed
 82→                                // (for ktlint-disable directive to have effect (when applied))
 83→                                // this will be rectified in the upcoming release(s)
 84→                                errorOffset.add(parsedLine.offset)
 85→                            }
 86→                        } else {
 87→                            // Allow ktlint-disable comments to exceed max line length
 88→                            if (!el.text.startsWith("// ktlint-disable")) {
 89→                                // if comment is the only thing on the line - fine, otherwise emit an error
 90→                                val prevLeaf = el.prevCodeSibling()
 91→                                if (prevLeaf != null && prevLeaf.startOffset >= parsedLine.offset) {
 92→                                    // fixme:
 93→                                    // normally we would emit here but due to API limitations we need to hold off until
 94→                                    // node spanning the same offset is 'visit'ed
 95→                                    // (for ktlint-disable directive to have effect (when applied))
 96→                                    // this will be rectified in the upcoming release(s)
 97→                                    errorOffset.add(parsedLine.offset)
 98→                                }
 99→                            }
100→                        }
101→                    }
102→                }
103→            rangeTree = RangeTree(errorOffset)
104→        } else if (!rangeTree.isEmpty() && node.psi is LeafPsiElement) {
105→            rangeTree
106→                .query(node.startOffset, node.startOffset + node.textLength)
107→                .forEach { offset ->
108→                    emit(offset, "Exceeded max line length ($maxLineLength)", false)
109→                }
110→        }
111→    }
112→
113→    private fun ASTNode.isPartOfRawMultiLineString() =
114→        parent(ElementType.STRING_TEMPLATE, strict = false)
115→            ?.let { it.firstChildNode.text == "\"\"\"" && it.textContains('\n') } == true
116→
117→    public companion object {
118→        public val IGNORE_BACKTICKED_IDENTIFIER_PROPERTY: EditorConfigProperty<Boolean> =
119→            EditorConfigProperty(
120→                type =
121→                    PropertyType.LowerCasingPropertyType(
122→                        "ktlint_ignore_back_ticked_identifier",
123→                        "Defines whether the backticked identifier (``) should be ignored",
124→                        PropertyType.PropertyValueParser.BOOLEAN_VALUE_PARSER,
125→                        setOf(true.toString(), false.toString()),
126→                    ),
127→                defaultValue = false,
128→            )
129→    }
130→}
131→
132→private fun ASTNode.getElementsPerLine(): List<ParsedLine> {
133→    val parsedLines = mutableListOf<ParsedLine>()
134→    val lines = text.split("\n")
135→    var offset = 0
136→    for (line in lines) {
137→        val elements = mutableListOf<ASTNode>()
138→        var el = psi.findElementAt(offset)?.node
139→        while (el != null && el.startOffset < offset + line.length) {
140→            elements.add(el)
141→            el = el.nextLeaf()
142→        }
143→        parsedLines.add(ParsedLine(line, offset, elements))
144→        offset += line.length + 1 // +1 for the newline which is stripped due to the splitting of the lines
145→    }
146→    return parsedLines
147→}
148→
149→private data class ParsedLine(
150→    val line: String,
151→    val offset: Int,
152→    val elements: List<ASTNode>,
153→) {
154→    fun lineLength(ignoreBackTickedIdentifier: Boolean): Int {
155→        return if (ignoreBackTickedIdentifier) {
156→            line.length - totalLengthBacktickedElements()
157→        } else {
158→            line.length
159→        }
160→    }
161→
162→    private fun totalLengthBacktickedElements(): Int {
163→        return elements
164→            .filterIsInstance(PsiElement::class.java)
165→            .filter { it.text.matches(BACKTICKED_IDENTIFIER_REGEX) }
166→            .sumOf(PsiElement::getTextLength)
167→    }
168→
169→    private companion object {
170→        val BACKTICKED_IDENTIFIER_REGEX = Regex("`.*`")
171→    }
172→}
173→
174→internal class RangeTree(seq: List<Int> = emptyList()) {
175→    private var emptyArrayView = ArrayView(0, 0)
176→    private var arr: IntArray = seq.toIntArray()
177→
178→    init {
179→        if (arr.isNotEmpty()) {
180→            arr.reduce { p, n ->
181→                require(p <= n) { "Input must be sorted" }
182→                n
183→            }
184→        }
185→    }
186→
187→    // runtime: O(log(n)+k), where k is number of matching points
188→    // space: O(1)
189→    fun query(
190→        vmin: Int,
191→        vmax: Int,
192→    ): ArrayView {
193→        var r = arr.size - 1
194→        if (r == -1 || vmax < arr[0] || arr[r] < vmin) {
195→            return emptyArrayView
196→        }
197→        // binary search for min(arr[l] >= vmin)
198→        var l = 0
199→        while (l < r) {
200→            val m = (r + l) / 2
201→            if (vmax < arr[m]) {
202→                r = m - 1
203→            } else if (arr[m] < vmin) {
204→                l = m + 1
205→            } else {
206→                // arr[l] ?<=? vmin <= arr[m] <= vmax ?<=? arr[r]
207→                if (vmin <= arr[l]) break else l++ // optimization
208→                r = m
209→            }
210→        }
211→        if (l > r || arr[l] < vmin) {
212→            return emptyArrayView
213→        }
214→        // find max(k) such as arr[k] < vmax
215→        var k = l
216→        while (k < arr.size) {
217→            if (arr[k] >= vmax) {
218→                break
219→            }
220→            k++
221→        }
222→        return ArrayView(l, k)
223→    }
224→
225→    fun isEmpty(): Boolean = arr.isEmpty()
226→
227→    inner class ArrayView(private var l: Int, private val r: Int) {
228→        val size: Int = r - l
229→
230→        fun get(i: Int): Int {
231→            if (i < 0 || i >= size) {
232→                throw IndexOutOfBoundsException()
233→            }
234→            return arr[l + i]
235→        }
236→
237→        inline fun forEach(cb: (v: Int) -> Unit) {
238→            var i = 0
239→            while (i < size) {
240→                cb(get(i++))
241→            }
242→        }
243→
244→        override fun toString(): String {
245→            if (l == r) {
246→                return "[]"
247→            }
248→            val sb = StringBuilder("[")
249→            var i = l
250→            while (i < r) {
251→                sb.append(arr[i]).append(", ")
252→                i++
253→            }
254→            sb.replace(sb.length - 2, sb.length, "")
255→            sb.append("]")
256→            return sb.toString()
257→        }
258→    }
259→}
260→
261→public val MAX_LINE_LENGTH_RULE_ID: RuleId = MaxLineLengthRule().ruleId
