public class KtlintSuppressionRule : StandardRule(id = "ktlint-suppression") {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        when (node.elementType) {
            EOL_COMMENT -> visitEolComment(node, emit, autoCorrect)
            BLOCK_COMMENT -> visitBlockComment(node, emit, autoCorrect)
        }
    }

    private fun visitEolComment(
        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        autoCorrect: Boolean,
    ) {
        val text =
            node
                .text
                .removePrefix("//")
                .trim()
        if (text.startsWith(KTLINT_DISABLE)) {
            emit(
                node.startOffset,
                "@Suppress annotation should be used instead of the 'ktlint-disable' directive",
                true,
            )
            if (autoCorrect) {
                removeEolComment(node)
            }
        }
    }

    private fun removeEolComment(node: ASTNode) {
        // Remove preceding whitespace on same line
        node
            .prevLeaf()
            ?.takeIf { it.isWhiteSpace() && !it.textContains('\n') }
            ?.let { (it as LeafPsiElement).rawRemove() }
        (node as LeafPsiElement).rawRemove()
    }

    private fun visitBlockComment(
        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        autoCorrect: Boolean,
    ) {
        val text =
            node
                .text
                .removePrefix("/*")
                .removeSuffix("*/")
                .trim()
        when {
            text.startsWith(KTLINT_DISABLE) -> {
                emit(
                    node.startOffset,
                    "@Suppress annotation should be used instead of the 'ktlint-disable' directive",
                    true,
                )
                if (autoCorrect) {
                    removeBlockComment(node)
                }
            }
            text.startsWith(KTLINT_ENABLE) -> {
                emit(
                    node.startOffset,
                    "The 'ktlint-enable' directive is obsolete after migrating to suppress annotations",
                    true,
                )
                if (autoCorrect) {
                    removeBlockComment(node)
                }
            }
        }
    }

    private fun removeBlockComment(node: ASTNode) {
        // Check if comment is on its own line
        val prevLeaf = node.prevLeaf()
        val nextLeaf = node.nextLeaf()

        val prevIsNewline = prevLeaf?.isWhiteSpace() == true && prevLeaf.textContains('\n')
        val nextIsNewline = nextLeaf?.isWhiteSpace() == true && nextLeaf.textContains('\n')

        when {
            prevIsNewline && nextIsNewline -> {
                // Comment is on its own line, remove the entire line
                (node as LeafPsiElement).rawRemove()
                // Remove the whitespace before (keeping only content after last newline)
                if (prevLeaf?.isWhiteSpace() == true && prevLeaf.textContains('\n')) {
                    val prevText = prevLeaf.text
                    val newText = prevText.substringAfterLast('\n')
                    if (newText.isEmpty()) {
                        (prevLeaf as LeafPsiElement).rawRemove()
                    } else {
                        (prevLeaf as LeafPsiElement).rawReplaceWithText("\n$newText")
                    }
                }
            }
            prevIsNewline && nextLeaf == null -> {
                // Comment is at end of file on its own line
                (node as LeafPsiElement).rawRemove()
                if (prevLeaf?.isWhiteSpace() == true && prevLeaf.textContains('\n')) {
                    val prevText = prevLeaf.text
                    // Keep content before the last newline (remove the newline before comment)
                    val newText = prevText.substringBeforeLast('\n')
                    if (newText.isEmpty()) {
                        (prevLeaf as LeafPsiElement).rawRemove()
                    } else {
                        (prevLeaf as LeafPsiElement).rawReplaceWithText(newText)
                    }
                }
            }
            else -> {
                // Comment is inline, just remove the comment and surrounding whitespace
                if (prevLeaf?.isWhiteSpace() == true && !prevLeaf.textContains('\n')) {
                    (prevLeaf as LeafPsiElement).rawRemove()
                }
                (node as LeafPsiElement).rawRemove()
                if (nextLeaf?.isWhiteSpace() == true && !nextLeaf.textContains('\n')) {
                    (nextLeaf as LeafPsiElement).rawRemove()
                }
            }
        }
    }

    private companion object {
        const val KTLINT_DISABLE = "ktlint-disable"
        const val KTLINT_ENABLE = "ktlint-enable"
    }
}

public val KTLINT_SUPPRESSION_RULE_ID: RuleId = KtlintSuppressionRule().ruleId
