 78→                if (autoCorrect) {
 79→                    removeBlockComment(node)
 80→                }
 81→            }
 82→            text.startsWith(KTLINT_ENABLE) -> {
 83→                emit(
 84→                    node.startOffset,
 85→                    "The 'ktlint-enable' directive is obsolete after migrating to suppress annotations",
 86→                    true,
 87→                )
 88→                if (autoCorrect) {
 89→                    removeBlockComment(node)
 90→                }
 91→            }
 92→        }
 93→    }
 94→
 95→    private fun removeBlockComment(node: ASTNode) {
 96→        // Check if comment is on its own line
 97→        val prevLeaf = node.prevLeaf()
 98→        val nextLeaf = node.nextLeaf()
 99→
100→        val prevIsNewline = prevLeaf?.isWhiteSpace() == true && prevLeaf.textContains('\n')
101→        val nextIsNewline = nextLeaf?.isWhiteSpace() == true && nextLeaf.textContains('\n')
102→
103→        when {
104→            prevIsNewline && nextIsNewline -> {
105→                // Comment is on its own line, remove the entire line
106→                (node as LeafPsiElement).rawRemove()
107→                // Remove the whitespace before (keeping only content after last newline)
108→                if (prevLeaf?.isWhiteSpace() == true && prevLeaf.textContains('\n')) {
109→                    val prevText = prevLeaf.text
110→                    val newText = prevText.substringAfterLast('\n')
111→                    if (newText.isEmpty()) {
112→                        (prevLeaf as LeafPsiElement).rawRemove()
113→                    } else {
114→                        (prevLeaf as LeafPsiElement).rawReplaceWithText("\n$newText")
115→                    }
116→                }
117→            }
118→            prevIsNewline && nextLeaf == null -> {
119→                // Comment is at end of file on its own line
120→                (node as LeafPsiElement).rawRemove()
121→                if (prevLeaf?.isWhiteSpace() == true && prevLeaf.textContains('\n')) {
122→                    val prevText = prevLeaf.text
123→                    // Keep content before the last newline (remove the newline before comment)
124→                    val newText = prevText.substringBeforeLast('\n')
125→                    if (newText.isEmpty()) {
126→                        (prevLeaf as LeafPsiElement).rawRemove()
127→                    } else {
128→                        (prevLeaf as LeafPsiElement).rawReplaceWithText(newText)
129→                    }
130→                }
131→            }
132→            else -> {
133→                // Comment is inline, just remove the comment and surrounding whitespace
134→                if (prevLeaf?.isWhiteSpace() == true && !prevLeaf.textContains('\n')) {
135→                    (prevLeaf as LeafPsiElement).rawRemove()
136→                }
137→                (node as LeafPsiElement).rawRemove()
138→                if (nextLeaf?.isWhiteSpace() == true && !nextLeaf.textContains('\n')) {
139→                    (nextLeaf as LeafPsiElement).rawRemove()
140→                }
141→            }
142→        }
143→    }
144→
145→    private companion object {
146→        const val KTLINT_DISABLE = "ktlint-disable"
147→        const val KTLINT_ENABLE = "ktlint-enable"
148→    }
149→}
